function (doc) {
  if (doc.type === "user" && doc.fts) {
    for (var i = 0; i < doc.fts.length; i++) {
      var e = doc.fts[i];
      var c = e.indexOf(":", 3);
      emit(e.substring(0, c), {
        memberOf: doc.memberOf || [],
        name: doc.name || null,
        email: doc.email || null,
        lastLogin: doc.lastLogin || null,
        updatedTimeUtc: doc.updatedTimeUtc || null
      });
    }
  }
}
